dashboard.definition:
{
	"title": "Alarm overview",
	"description": "",
	"inputs": {
		"input_global_trp": {
			"options": {
				"defaultValue": "-30d@d,@d",
				"token": "global_time"
			},
			"title": "Global Time Range",
			"type": "input.timerange"
		},
		"input_sajodWfb": {
			"options": {
				"items": [
					{
						"label": "All",
						"value": "*"
					}
				],
				"defaultValue": "*",
				"token": "selected_well"
			},
			"title": "Well Bore Code",
			"type": "input.dropdown",
			"dataSources": {
				"primary": "ds_AeKD1ru4"
			}
		}
	},
	"defaults": {
		"dataSources": {
			"ds.search": {
				"options": {
					"queryParameters": {
						"earliest": "$global_time.earliest$",
						"latest": "$global_time.latest$"
					}
				}
			}
		}
	},
	"visualizations": {
		"viz_56AG8P0i": {
			"type": "splunk.bar",
			"options": {
				"stackMode": "stacked",
				"dataValuesDisplay": "all"
			},
			"dataSources": {
				"primary": "ds_JHQfhxnV"
			},
			"title": "ESP alarms by well",
			"eventHandlers": [
				{
					"type": "drilldown.linkToDashboard",
					"options": {
						"app": "oilgas_splunk_app",
						"dashboard": "well_historic_data_studio",
						"newTab": true,
						"tokens": [
							{
								"token": "selected_well",
								"value": "row.WELL_BORE_CODE.value"
							}
						]
					}
				}
			]
		},
		"viz_3K5IrgUa": {
			"type": "splunk.column",
			"options": {
				"dataValuesDisplay": "all",
				"overlayFields": [],
				"showIndependentYRanges": true,
				"columnGrouping": "overlay",
				"seriesColors": [
					"#009CEB",
					"#00CDAF",
					"#DD9900",
					"#FF677B",
					"#CB2196",
					"#813193",
					"#0051B5",
					"#008C80",
					"#99B100",
					"#FFA476",
					"#FF6ACE",
					"#AE8CFF",
					"#00689D",
					"#00490A",
					"#465D00",
					"#9D6300",
					"#F6540B",
					"#FF969E",
					"#E47BFE"
				],
				"stackMode": "stacked"
			},
			"dataSources": {
				"primary": "ds_LNAnstM8"
			},
			"title": "ESP alarms by type"
		},
		"viz_9TotiWdZ": {
			"type": "splunk.table",
			"dataSources": {
				"primary": "ds_kP1qHdNu"
			},
			"title": "ESP alarms reason"
		},
		"viz_pegU55md": {
			"type": "splunk.column",
			"dataSources": {
				"primary": "ds_uUHy2CIa"
			},
			"options": {
				"showTooltip": false,
				"showIndependentYRanges": true
			},
			"title": "ESP alarms dynamics"
		},
		"viz_xe2v4qTN": {
			"type": "splunk.table",
			"options": {
				"columnFormat": {
					"Time": {
						"width": 60
					},
					"Alarm Title": {
						"width": 60
					}
				}
			},
			"dataSources": {
				"primary": "ds_rycS1HWU"
			},
			"title": "ESP alarms description"
		},
		"viz_6rtFI9AI": {
			"type": "splunk.bar",
			"options": {
				"dataValuesDisplay": "all",
				"stackMode": "stacked"
			},
			"dataSources": {
				"primary": "ds_SN3fqYti"
			},
			"title": "Well alarms count",
			"eventHandlers": [
				{
					"type": "drilldown.setToken",
					"options": {
						"tokens": [
							{
								"token": "selected_well",
								"key": "row.WELL_BORE_CODE.value"
							}
						]
					}
				},
				{
					"type": "drilldown.linkToDashboard",
					"options": {
						"app": "oilgas_splunk_app",
						"dashboard": "well_historic_data_studio",
						"newTab": true,
						"tokens": [
							{
								"token": "selected_well",
								"value": "row.WELL_BORE_CODE.value"
							}
						]
					}
				}
			]
		},
		"viz_e7fwYx6A": {
			"type": "splunk.column",
			"options": {
				"dataValuesDisplay": "all",
				"stackMode": "stacked"
			},
			"dataSources": {
				"primary": "ds_mFMMpptu"
			},
			"title": "Well alarms by type"
		},
		"viz_lKUfl2pJ": {
			"type": "splunk.column",
			"dataSources": {
				"primary": "ds_D33MJsXp"
			},
			"title": "Well alarms dynamics"
		},
		"viz_MN4T4L5w": {
			"type": "splunk.table",
			"dataSources": {
				"primary": "ds_T62xJNjO"
			},
			"title": "Well alarms reason",
			"options": {
				"columnFormat": {
					"Well metric": {
						"width": 105
					},
					"Well Bore Code": {
						"width": 72
					},
					"Time": {
						"width": 68
					}
				}
			},
			"eventHandlers": []
		},
		"viz_P0WBxBZW": {
			"type": "splunk.table",
			"options": {
				"columnFormat": {
					"Well metric": {
						"width": 91
					},
					"Time": {
						"width": 60
					},
					"Alarm Title": {
						"width": 79
					}
				}
			},
			"dataSources": {
				"primary": "ds_aecSVkNi"
			},
			"title": "Well alarms description",
			"eventHandlers": []
		}
	},
	"dataSources": {
		"ds_AeKD1ru4": {
			"type": "ds.search",
			"options": {
				"query": "| datamodel OilGas Main_Data search\n| dedup WELL_BORE_CODE\n| table WELL_BORE_CODE"
			},
			"name": "selected_well"
		},
		"ds_JHQfhxnV": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup esp_alarms\n| eval earliest_epoch = relative_time(now(), \"$global_time.earliest$\"), latest_epoch = \"$global_time.latest$\"\n| where _time >= earliest_epoch AND _time <= latest_epoch\n| stats count by WELL_BORE_CODE\n| sort -count"
			},
			"name": "query_esp_alarm_qty_by_well"
		},
		"ds_LNAnstM8": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup esp_alarms\n| eval earliest_epoch = relative_time(now(), \"$global_time.earliest$\"), latest_epoch = \"$global_time.latest$\"\n| where _time >= earliest_epoch AND _time <= latest_epoch AND if(\"$selected_well$\"=\"*\", 1=1, WELL_BORE_CODE=\"$selected_well$\") \n| chart count over metric by alert_reason",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "query_count_esp_alarms_by_type"
		},
		"ds_kP1qHdNu": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup esp_alarms\n| eval earliest_epoch = relative_time(now(), \"$global_time.earliest$\"), latest_epoch = \"$global_time.latest$\"\n| where _time >= earliest_epoch AND _time <= latest_epoch AND if(\"$selected_well$\"=\"*\", 1=1, WELL_BORE_CODE=\"$selected_well$\") \n| sort -_time\n| eval formatted_time = strftime(_time, \"%Y-%m-%d %H:%M:%S\")\n| rename formatted_time AS \"Time\", WELL_BORE_CODE AS \"Well Bore Code\", metric AS \"ESP metric\", value AS \"Value\", min AS \"Min\", max AS \"Max\", alert_reason AS \"Alarm Reason\"\n| table \"Time\" \"Well Bore Code\" \"ESP metric\" \"Value\" \"Min\" \"Max\" \"Alarm Reason\"",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "query_esp_alarm_reason"
		},
		"ds_uUHy2CIa": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup esp_alarms\n| eval earliest_epoch = relative_time(now(), \"$global_time.earliest$\"), latest_epoch = \"$global_time.latest$\"\n| where _time >= earliest_epoch AND _time <= latest_epoch AND if(\"$selected_well$\"=\"*\", 1=1, WELL_BORE_CODE=\"$selected_well$\")\n| timechart count as alarm_count by metric",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "query_esp_alarms_timechart"
		},
		"ds_rycS1HWU": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup esp_alarms\n| eval earliest_epoch = relative_time(now(), \"$global_time.earliest$\"), latest_epoch = \"$global_time.latest$\"\n| where _time >= earliest_epoch AND _time <= latest_epoch AND if(\"$selected_well$\"=\"*\", 1=1, WELL_BORE_CODE=\"$selected_well$\") \n| sort -_time\n| eval formatted_time = strftime(_time, \"%Y-%m-%d %H:%M:%S\")\n| eval alert_title = `alert_title(alert_reason, WELL_BORE_CODE, metric)`\n| eval alert_description = `alert_description(alert_reason, WELL_BORE_CODE, metric, value, min, max)`\n| rename formatted_time AS \"Time\", alert_title AS \"Alarm Title\", alert_description AS \"Alarm Description\"\n| table \"Time\", \"Alarm Title\", \"Alarm Description\"",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "query_esp_alarm_title_and_description"
		},
		"ds_SN3fqYti": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup well_alarms\n| eval earliest_epoch = relative_time(now(), \"$global_time.earliest$\"), latest_epoch = \"$global_time.latest$\"\n| where _time >= earliest_epoch AND _time <= latest_epoch\n| stats count by WELL_BORE_CODE\n| sort -count",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "query_well_alarm_qty_by_well"
		},
		"ds_mFMMpptu": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup well_alarms\n| eval earliest_epoch = relative_time(now(), \"$global_time.earliest$\"), latest_epoch = \"$global_time.latest$\"\n| where _time >= earliest_epoch AND _time <= latest_epoch AND if(\"$selected_well$\"=\"*\", 1=1, WELL_BORE_CODE=\"$selected_well$\") \n| chart count over metric by alert_reason",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "query_count_well_alarms_by_type"
		},
		"ds_D33MJsXp": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup well_alarms\n| eval earliest_epoch = relative_time(now(), \"$global_time.earliest$\"), latest_epoch = \"$global_time.latest$\"\n| where _time >= earliest_epoch AND _time <= latest_epoch AND if(\"$selected_well$\"=\"*\", 1=1, WELL_BORE_CODE=\"$selected_well$\")\n| timechart count as alarm_count by metric",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "query_well_alarms_timechart"
		},
		"ds_T62xJNjO": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup well_alarms\n| eval earliest_epoch = relative_time(now(), \"$global_time.earliest$\"), latest_epoch = \"$global_time.latest$\"\n| where _time >= earliest_epoch AND _time <= latest_epoch AND if(\"$selected_well$\"=\"*\", 1=1, WELL_BORE_CODE=\"$selected_well$\") \n| sort -_time\n| eval formatted_time = strftime(_time, \"%Y-%m-%d %H:%M:%S\")\n| rename formatted_time AS \"Time\", WELL_BORE_CODE AS \"Well Bore Code\", metric AS \"Well metric\", value AS \"Value\", min AS \"Min\", max AS \"Max\", alert_reason AS \"Alarm Reason\"\n| table \"Time\" \"Well Bore Code\" \"Well metric\" \"Value\" \"Min\" \"Max\" \"Alarm Reason\"",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "query_well_alarm_reason"
		},
		"ds_aecSVkNi": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup well_alarms\n| eval earliest_epoch = relative_time(now(), \"$global_time.earliest$\"), latest_epoch = \"$global_time.latest$\"\n| where _time >= earliest_epoch AND _time <= latest_epoch AND if(\"$selected_well$\"=\"*\", 1=1, WELL_BORE_CODE=\"$selected_well$\") \n| sort -_time\n| eval formatted_time = strftime(_time, \"%Y-%m-%d %H:%M:%S\")\n| eval alert_title = `alert_title(alert_reason, WELL_BORE_CODE, metric)`\n| eval alert_description = `alert_description(alert_reason, WELL_BORE_CODE, metric, value, min, max)`\n| rename formatted_time AS \"Time\", alert_title AS \"Alarm Title\", alert_description AS \"Alarm Description\"\n| table \"Time\", \"Alarm Title\", \"Alarm Description\"",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "query_well_alarm_title_and_description"
		}
	},
